import { Grid, Paper,Stack,Button,Typography,  } from '@mui/material'
import React from 'react'
import { useNavigate } from 'react-router-dom'
import signpng from './signupfinal.png'



import { makeStyles } from '@mui/styles';

const useStyles = makeStyles((theme) => ({
  image: {
    width: '200px',
    height: 'auto',
  },
}));


export const Signup = () => {
    const navigate = useNavigate()
    const classes = useStyles();

return (
    <Grid container
    justifyContent="center"
    alignItems="center"
    style={{ minHeight: '100vh' }}>


        <Paper sx={{padding:'25px', width: 'auto', height: '300px'}} elevation={10}>
            
        <Stack justifyContent='center' alignItems='center' spacing={20} direction='row'>
        <img src={signpng} alt='The signup ' className={classes.image}  />
        <Typography variant='h2'>Hello world how are you</Typography>
        <Stack direction='vertical'>
        
        <Button variant='contained' onClick={()=>{navigate('/signup')}}>Signup</Button>

        </Stack>
    </Stack>

    
        </Paper>


    </Grid>
  )
}
